import { toast } from "sonner";

type ErrorBag = Record<string, unknown>;

function findFirstError(value: unknown): string | undefined {
    if (typeof value === "string" && value.trim()) {
        return value;
    }

    if (Array.isArray(value)) {
        for (const item of value) {
            const error = findFirstError(item);

            if (error) {
                return error;
            }
        }

        return undefined;
    }

    if (value && typeof value === "object") {
        for (const item of Object.values(value as ErrorBag)) {
            const error = findFirstError(item);

            if (error) {
                return error;
            }
        }
    }

    return undefined;
}

export function firstFormError(errors: unknown): string | undefined {
    return findFirstError(errors);
}

export function toastFirstFormError(errors: unknown): void {
    const message = firstFormError(errors);

    if (message) {
        toast.error(message);
    }
}
